func (q *Queries) ListVulnerabilityDefinitionsByProject(ctx context.Context, projectID uint64) ([]VulnerabilityDefinition, error) {
	rows, err := q.db.QueryContext(ctx, listVulnerabilityDefinitionsByProject, projectID)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []VulnerabilityDefinition{}
	for rows.Next() {
		var i VulnerabilityDefinition
		if err := rows.Scan(
			&i.ID,
			&i.TenantID,
			&i.OrgID,
			&i.ProjectID,
			&i.RuleID,
			&i.CveID,
			&i.Title,
			&i.Description,
			&i.Severity,
			&i.CpePattern,
			&i.Remediation,
			&i.Source,
			&i.Enabled,
			&i.CreatedAt,
			&i.UpdatedAt,
			&i.CreatedBy,
			&i.UpdatedBy,
			&i.DeletedAt,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Close(); err != nil {
		return nil, err
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

